import pyotp
import qrcode
import base64
import time

class TOTPAuthenticator:
    def __init__(self, issuer_name="MFA System"):
        self.issuer_name = issuer_name

    def generate_secret(self):
        """Generates a new random TOTP secret."""
        return pyotp.random_base32()

    def get_provisioning_uri(self, secret, account_name):
        """
        Generates the provisioning URI for the authenticator app.
        This URI is used to create the QR code.
        """
        return pyotp.TOTP(secret).provisioning_uri(
            name=account_name,
            issuer_name=self.issuer_name
        )

    def generate_qr_code_svg(self, secret, account_name):
        """
        Generates an SVG string of the QR code from the provisioning URI.
        """
        provisioning_uri = self.get_provisioning_uri(secret, account_name)
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(provisioning_uri)
        qr.make(fit=True)
        img = qr.make_image(fill_color="black", back_color="white")
        # For simplicity, returning SVG as string.
        # In a real app, you might save it to a file or embed in HTML.
        return img.get_image()._repr_svg_() # This is a pillow-simd method, usually works with PIL

    def generate_qr_code_base64_png(self, secret, account_name):
        """
        Generates a PNG image of the QR code, encoded in base64.
        This is suitable for embedding directly into HTML as <img src="data:image/png;base64,...">
        """
        provisioning_uri = self.get_provisioning_uri(secret, account_name)
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(provisioning_uri)
        qr.make(fit=True)
        img = qr.make_image(fill_color="black", back_color="white")

        from io import BytesIO
        buffer = BytesIO()
        img.save(buffer, format="PNG")
        return base64.b64encode(buffer.getvalue()).decode('utf-8')

    def verify_totp(self, secret, user_input_totp_code):
        """
        Verifies if the user-provided TOTP code is valid for the given secret
        at the current time.
        """
        totp = pyotp.TOTP(secret)
        # Verify with a leeway for time drift (e.g., 30 seconds before/after current window)
        # For TOTP, pyotp.verify() automatically handles the current and adjacent windows by default.
        # It checks current, previous, and next 30-second windows.
        return totp.verify(user_input_totp_code)

    def get_current_totp(self, secret):
        """
        Returns the current valid TOTP code for testing purposes.
        In a real application, this would only be used for internal testing
        or to show the expected code (e.g., for admin debugging), not for users.
        """
        totp = pyotp.TOTP(secret)
        return totp.now()

